import{_ as a,o as i,c as s,ag as l}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"gateway","description":"OpenClaw Gateway CLI (`openclaw gateway`) — 게이트웨이 실행, 쿼리, 탐색","frontmatter":{"title":"gateway","description":"OpenClaw Gateway CLI (`openclaw gateway`) — 게이트웨이 실행, 쿼리, 탐색"},"headers":[],"relativePath":"cli/gateway.md","filePath":"cli/gateway.md","lastUpdated":null}'),o={name:"cli/gateway.md"};function t(d,e,c,n,p,h){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="gateway-cli" tabindex="-1">Gateway CLI <a class="header-anchor" href="#gateway-cli" aria-label="Permalink to &quot;Gateway CLI&quot;">​</a></h1><p>Gateway는 OpenClaw의 WebSocket 서버 (채널, 노드, 세션, 훅)입니다.</p><p>이 페이지의 하위 명령은 <code>openclaw gateway …</code> 아래에 있습니다.</p><p>관련 문서:</p><ul><li><a href="/openclaw-docs-ko/gateway/bonjour">/gateway/bonjour</a></li><li><a href="/openclaw-docs-ko/gateway/discovery">/gateway/discovery</a></li><li><a href="/openclaw-docs-ko/gateway/configuration">/gateway/configuration</a></li></ul><h2 id="gateway-실행" tabindex="-1">Gateway 실행 <a class="header-anchor" href="#gateway-실행" aria-label="Permalink to &quot;Gateway 실행&quot;">​</a></h2><p>로컬 Gateway 프로세스 실행:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre></div><p>포그라운드 별칭:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p>참고사항:</p><ul><li>기본적으로 Gateway는 <code>~/.openclaw/openclaw.json</code>에 <code>gateway.mode=local</code>이 설정되어 있지 않으면 시작을 거부합니다. 임시/개발 실행에는 <code>--allow-unconfigured</code>를 사용하세요.</li><li><code>openclaw onboard --mode local</code> 및 <code>openclaw setup</code>은 <code>gateway.mode=local</code>을 작성해야 합니다. 파일이 존재하지만 <code>gateway.mode</code>가 누락된 경우 암묵적으로 로컬 모드를 가정하는 대신 손상되거나 덮어쓰여진 구성으로 처리하고 수리하세요.</li><li>파일이 존재하고 <code>gateway.mode</code>가 누락된 경우 Gateway는 이를 의심스러운 구성 손상으로 처리하고 대신 로컬을 추측하는 것을 거부합니다.</li><li>인증 없이 루프백 이상의 바인딩은 차단됩니다 (안전 가드레일).</li><li><code>SIGUSR1</code>은 승인된 경우 (<code>commands.restart</code>가 기본적으로 활성화됨; 수동 재시작을 차단하려면 <code>commands.restart: false</code>로 설정하고 게이트웨이 툴/구성 적용/업데이트는 허용 유지) 인프로세스 재시작을 트리거합니다.</li><li><code>SIGINT</code>/<code>SIGTERM</code> 핸들러는 게이트웨이 프로세스를 중지하지만 사용자 정의 터미널 상태를 복원하지 않습니다. CLI를 TUI 또는 원시 모드 입력으로 래핑하는 경우 종료 전에 터미널을 복원하세요.</li></ul><h3 id="옵션" tabindex="-1">옵션 <a class="header-anchor" href="#옵션" aria-label="Permalink to &quot;옵션&quot;">​</a></h3><ul><li><code>--port &lt;port&gt;</code>: WebSocket 포트 (기본값은 구성/env에서 옴; 보통 <code>18789</code>).</li><li><code>--bind &lt;loopback|lan|tailnet|auto|custom&gt;</code>: 리스너 바인드 모드.</li><li><code>--auth &lt;token|password&gt;</code>: 인증 모드 재정의.</li><li><code>--token &lt;token&gt;</code>: 토큰 재정의 (프로세스에 <code>OPENCLAW_GATEWAY_TOKEN</code>도 설정).</li><li><code>--password &lt;password&gt;</code>: 비밀번호 재정의. 경고: 인라인 비밀번호는 로컬 프로세스 목록에 노출될 수 있습니다.</li><li><code>--password-file &lt;path&gt;</code>: 파일에서 게이트웨이 비밀번호 읽기.</li><li><code>--tailscale &lt;off|serve|funnel&gt;</code>: Tailscale을 통해 Gateway 노출.</li><li><code>--tailscale-reset-on-exit</code>: 종료 시 Tailscale serve/funnel 구성 재설정.</li><li><code>--allow-unconfigured</code>: 구성에 <code>gateway.mode=local</code> 없이 게이트웨이 시작 허용. 이것은 임시/개발 부트스트랩에만 시작 가드를 우회하며 구성 파일을 작성하거나 수리하지 않습니다.</li><li><code>--dev</code>: 누락된 경우 개발 구성 + 워크스페이스 생성 (BOOTSTRAP.md 건너뜀).</li><li><code>--reset</code>: 개발 구성 + 자격 증명 + 세션 + 워크스페이스 재설정 (<code>--dev</code> 필요).</li><li><code>--force</code>: 시작 전에 선택된 포트의 기존 리스너 종료.</li><li><code>--verbose</code>: 상세 로그.</li><li><code>--cli-backend-logs</code>: 콘솔에서 CLI 백엔드 로그만 표시 (stdout/stderr 활성화).</li><li><code>--ws-log &lt;auto|full|compact&gt;</code>: WebSocket 로그 스타일 (기본값 <code>auto</code>).</li><li><code>--compact</code>: <code>--ws-log compact</code>의 별칭.</li><li><code>--raw-stream</code>: jsonl에 원시 모델 스트림 이벤트 기록.</li><li><code>--raw-stream-path &lt;path&gt;</code>: 원시 스트림 jsonl 경로.</li></ul><h2 id="실행-중인-gateway-쿼리" tabindex="-1">실행 중인 Gateway 쿼리 <a class="header-anchor" href="#실행-중인-gateway-쿼리" aria-label="Permalink to &quot;실행 중인 Gateway 쿼리&quot;">​</a></h2><p>모든 쿼리 명령은 WebSocket RPC를 사용합니다.</p><p>출력 모드:</p><ul><li>기본: 사람이 읽을 수 있음 (TTY에서 색상).</li><li><code>--json</code>: 기계 판독 가능한 JSON (스타일링/스피너 없음).</li><li><code>--no-color</code> (또는 <code>NO_COLOR=1</code>): 사람이 읽는 레이아웃을 유지하면서 ANSI 비활성화.</li></ul><p>공유 옵션 (지원되는 경우):</p><ul><li><code>--url &lt;url&gt;</code>: Gateway WebSocket URL.</li><li><code>--token &lt;token&gt;</code>: Gateway 토큰.</li><li><code>--password &lt;password&gt;</code>: Gateway 비밀번호.</li><li><code>--timeout &lt;ms&gt;</code>: 타임아웃/예산 (명령마다 다름).</li><li><code>--expect-final</code>: &quot;최종&quot; 응답 대기 (에이전트 호출).</li></ul><p>참고: <code>--url</code>을 설정하면 CLI는 구성 또는 환경 자격 증명으로 폴백하지 않습니다. <code>--token</code> 또는 <code>--password</code>를 명시적으로 전달하세요. 명시적 자격 증명 누락은 오류입니다.</p><h3 id="gateway-health" tabindex="-1"><code>gateway health</code> <a class="header-anchor" href="#gateway-health" aria-label="Permalink to &quot;`gateway health`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://127.0.0.1:18789</span></span></code></pre></div><h3 id="gateway-usage-cost" tabindex="-1"><code>gateway usage-cost</code> <a class="header-anchor" href="#gateway-usage-cost" aria-label="Permalink to &quot;`gateway usage-cost`&quot;">​</a></h3><p>세션 로그에서 사용 비용 요약 가져오기.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usage-cost</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usage-cost</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --days</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usage-cost</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>옵션:</p><ul><li><code>--days &lt;days&gt;</code>: 포함할 일 수 (기본값 <code>30</code>).</li></ul><h3 id="gateway-status" tabindex="-1"><code>gateway status</code> <a class="header-anchor" href="#gateway-status" aria-label="Permalink to &quot;`gateway status`&quot;">​</a></h3><p><code>gateway status</code>는 Gateway 서비스 (launchd/systemd/schtasks)와 선택적 RPC 프로브를 표시합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --require-rpc</span></span></code></pre></div><p>옵션:</p><ul><li><code>--url &lt;url&gt;</code>: 명시적 프로브 대상 추가. 구성된 원격 + 로컬호스트는 여전히 프로브됩니다.</li><li><code>--token &lt;token&gt;</code>: 프로브를 위한 토큰 인증.</li><li><code>--password &lt;password&gt;</code>: 프로브를 위한 비밀번호 인증.</li><li><code>--timeout &lt;ms&gt;</code>: 프로브 타임아웃 (기본값 <code>10000</code>).</li><li><code>--no-probe</code>: RPC 프로브 건너뜀 (서비스 전용 뷰).</li><li><code>--deep</code>: 시스템 수준 서비스도 스캔.</li><li><code>--require-rpc</code>: RPC 프로브 실패 시 0이 아닌 종료. <code>--no-probe</code>와 결합할 수 없음.</li></ul><p>참고사항:</p><ul><li><code>gateway status</code>는 로컬 CLI 구성이 누락되거나 유효하지 않아도 진단을 위해 사용 가능합니다.</li><li><code>gateway status</code>는 가능한 경우 프로브 인증을 위해 구성된 인증 SecretRef를 확인합니다.</li><li>이 명령 경로에서 필수 인증 SecretRef가 확인되지 않은 경우 프로브 연결/인증이 실패할 때 <code>gateway status --json</code>은 <code>rpc.authWarning</code>을 보고합니다.</li><li>프로브가 성공하면 확인되지 않은 인증 ref 경고는 억제됩니다.</li><li>스크립트 및 자동화에서 리스닝 서비스로 충분하지 않고 Gateway RPC 자체가 정상이어야 할 때 <code>--require-rpc</code>를 사용하세요.</li><li><code>--deep</code>은 추가 launchd/systemd/schtasks 설치에 대한 최선의 스캔을 추가합니다.</li><li>사람이 읽을 수 있는 출력에는 확인된 파일 로그 경로와 프로파일 또는 상태 디렉터리 드리프트 진단에 도움이 되는 CLI 대 서비스 구성 경로/유효성 스냅샷이 포함됩니다.</li><li>Linux systemd 설치에서 서비스 인증 드리프트 검사는 단위에서 <code>Environment=</code> 및 <code>EnvironmentFile=</code> 값을 모두 읽습니다 (<code>%h</code>, 인용된 경로, 여러 파일, 선택적 <code>-</code> 파일 포함).</li><li>드리프트 검사는 병합된 런타임 env를 사용하여 <code>gateway.auth.token</code> SecretRef를 확인합니다.</li><li>토큰 인증이 효과적으로 활성화되지 않은 경우 토큰 드리프트 검사는 구성 토큰 확인을 건너뜁니다.</li></ul><h3 id="gateway-probe" tabindex="-1"><code>gateway probe</code> <a class="header-anchor" href="#gateway-probe" aria-label="Permalink to &quot;`gateway probe`&quot;">​</a></h3><p><code>gateway probe</code>는 &quot;모든 것을 디버그&quot; 명령입니다. 항상 다음을 프로브합니다:</p><ul><li>구성된 원격 게이트웨이 (설정된 경우), 그리고</li><li>로컬호스트 (루프백) <strong>원격이 구성된 경우에도</strong>.</li></ul><p><code>--url</code>을 전달하면 해당 명시적 대상이 두 대상 앞에 추가됩니다. 사람이 읽을 수 있는 출력은 다음과 같이 대상에 레이블을 붙입니다:</p><ul><li><code>URL (explicit)</code></li><li><code>Remote (configured)</code> 또는 <code>Remote (configured, inactive)</code></li><li><code>Local loopback</code></li></ul><p>여러 게이트웨이에 도달 가능한 경우 모두 출력합니다. 여러 게이트웨이는 격리된 프로파일/포트를 사용할 때 지원되지만 (예: 구조 봇) 대부분의 설치는 여전히 단일 게이트웨이를 실행합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> probe</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> probe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>해석:</p><ul><li><code>Reachable: yes</code>는 하나 이상의 대상이 WebSocket 연결을 수락했음을 의미합니다.</li><li><code>RPC: ok</code>는 세부 RPC 호출 (<code>health</code>/<code>status</code>/<code>system-presence</code>/<code>config.get</code>)도 성공했음을 의미합니다.</li><li><code>RPC: limited - missing scope: operator.read</code>는 연결이 성공했지만 세부 RPC가 범위 제한됨을 의미합니다. 이것은 완전한 실패가 아닌 <strong>저하된</strong> 도달 가능성으로 보고됩니다.</li><li>종료 코드는 프로브된 대상에 도달할 수 없는 경우에만 0이 아닙니다.</li></ul><p>JSON 참고사항 (<code>--json</code>):</p><ul><li>최상위: <ul><li><code>ok</code>: 하나 이상의 대상에 도달 가능.</li><li><code>degraded</code>: 하나 이상의 대상에 범위 제한된 세부 RPC가 있음.</li><li><code>primaryTargetId</code>: 이 순서로 활성 우승자로 처리할 최상의 대상: 명시적 URL, SSH 터널, 구성된 원격, 그 다음 로컬 루프백.</li><li><code>warnings[]</code>: <code>code</code>, <code>message</code>, 선택적 <code>targetIds</code>가 있는 최선의 경고 레코드.</li><li><code>network</code>: 현재 구성 및 호스트 네트워킹에서 파생된 로컬 루프백/tailnet URL 힌트.</li><li><code>discovery.timeoutMs</code> 및 <code>discovery.count</code>: 이 프로브 패스에 사용된 실제 탐색 예산/결과 수.</li></ul></li><li>대상별 (<code>targets[].connect</code>): <ul><li><code>ok</code>: 연결 + 저하 분류 후 도달 가능성.</li><li><code>rpcOk</code>: 전체 세부 RPC 성공.</li><li><code>scopeLimited</code>: 누락된 운영자 범위로 인해 세부 RPC가 실패함.</li></ul></li></ul><p>일반 경고 코드:</p><ul><li><code>ssh_tunnel_failed</code>: SSH 터널 설정 실패; 명령이 직접 프로브로 폴백됨.</li><li><code>multiple_gateways</code>: 하나 이상의 대상에 도달 가능; 구조 봇과 같이 격리된 프로파일을 의도적으로 실행하지 않는 한 이례적.</li><li><code>auth_secretref_unresolved</code>: 실패한 대상에 대해 구성된 인증 SecretRef를 확인할 수 없었음.</li><li><code>probe_scope_limited</code>: WebSocket 연결은 성공했지만 누락된 <code>operator.read</code>로 인해 세부 RPC가 제한됨.</li></ul><h4 id="ssh를-통한-원격-mac-앱-패리티" tabindex="-1">SSH를 통한 원격 (Mac 앱 패리티) <a class="header-anchor" href="#ssh를-통한-원격-mac-앱-패리티" aria-label="Permalink to &quot;SSH를 통한 원격 (Mac 앱 패리티)&quot;">​</a></h4><p>macOS 앱 &quot;SSH를 통한 원격&quot; 모드는 로컬 포트 포워드를 사용하여 원격 게이트웨이 (루프백에만 바인딩될 수 있음)가 <code>ws://127.0.0.1:&lt;port&gt;</code>에서 도달 가능하게 합니다.</p><p>CLI 동등:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> probe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@gateway-host</span></span></code></pre></div><p>옵션:</p><ul><li><code>--ssh &lt;target&gt;</code>: <code>user@host</code> 또는 <code>user@host:port</code> (포트 기본값 <code>22</code>).</li><li><code>--ssh-identity &lt;path&gt;</code>: ID 파일.</li><li><code>--ssh-auto</code>: 확인된 탐색 엔드포인트 (<code>local.</code> 더하기 구성된 광역 도메인, 있는 경우)에서 첫 번째 발견된 게이트웨이 호스트를 SSH 대상으로 선택. TXT 전용 힌트는 무시됨.</li></ul><p>구성 (선택 사항, 기본값으로 사용):</p><ul><li><code>gateway.remote.sshTarget</code></li><li><code>gateway.remote.sshIdentity</code></li></ul><h3 id="gateway-call-method" tabindex="-1"><code>gateway call &lt;method&gt;</code> <a class="header-anchor" href="#gateway-call-method" aria-label="Permalink to &quot;`gateway call &lt;method&gt;`&quot;">​</a></h3><p>저수준 RPC 도우미.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs.tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;sinceMs&quot;: 60000}&#39;</span></span></code></pre></div><p>옵션:</p><ul><li><code>--params &lt;json&gt;</code>: 매개변수를 위한 JSON 객체 문자열 (기본값 <code>{}</code>)</li><li><code>--url &lt;url&gt;</code></li><li><code>--token &lt;token&gt;</code></li><li><code>--password &lt;password&gt;</code></li><li><code>--timeout &lt;ms&gt;</code></li><li><code>--expect-final</code></li><li><code>--json</code></li></ul><p>참고사항:</p><ul><li><code>--params</code>는 유효한 JSON이어야 합니다.</li><li><code>--expect-final</code>은 주로 최종 페이로드 전에 중간 이벤트를 스트리밍하는 에이전트 스타일 RPC에 사용됩니다.</li></ul><h2 id="gateway-서비스-관리" tabindex="-1">Gateway 서비스 관리 <a class="header-anchor" href="#gateway-서비스-관리" aria-label="Permalink to &quot;Gateway 서비스 관리&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span></code></pre></div><p>명령 옵션:</p><ul><li><code>gateway status</code>: <code>--url</code>, <code>--token</code>, <code>--password</code>, <code>--timeout</code>, <code>--no-probe</code>, <code>--require-rpc</code>, <code>--deep</code>, <code>--json</code></li><li><code>gateway install</code>: <code>--port</code>, <code>--runtime &lt;node|bun&gt;</code>, <code>--token</code>, <code>--force</code>, <code>--json</code></li><li><code>gateway uninstall|start|stop|restart</code>: <code>--json</code></li></ul><p>참고사항:</p><ul><li><code>gateway install</code>은 <code>--port</code>, <code>--runtime</code>, <code>--token</code>, <code>--force</code>, <code>--json</code>을 지원합니다.</li><li>토큰 인증에 토큰이 필요하고 <code>gateway.auth.token</code>이 SecretRef 관리인 경우 <code>gateway install</code>은 SecretRef가 확인 가능한지 검증하지만 확인된 토큰을 서비스 환경 메타데이터에 유지하지 않습니다.</li><li>토큰 인증에 토큰이 필요하고 구성된 토큰 SecretRef가 확인되지 않으면 설치가 실패 처리됩니다.</li><li><code>gateway run</code>의 비밀번호 인증에는 인라인 <code>--password</code>보다 <code>OPENCLAW_GATEWAY_PASSWORD</code>, <code>--password-file</code>, 또는 SecretRef 기반 <code>gateway.auth.password</code>를 선호하세요.</li><li>추론된 인증 모드에서 셸 전용 <code>OPENCLAW_GATEWAY_PASSWORD</code>는 설치 토큰 요구 사항을 완화하지 않습니다. 관리 서비스를 설치할 때 지속 가능한 구성 (<code>gateway.auth.password</code> 또는 구성 <code>env</code>)을 사용하세요.</li><li><code>gateway.auth.token</code>과 <code>gateway.auth.password</code>가 모두 구성되고 <code>gateway.auth.mode</code>가 설정되지 않은 경우 모드가 명시적으로 설정될 때까지 설치가 차단됩니다.</li><li>라이프사이클 명령은 스크립팅을 위해 <code>--json</code>을 허용합니다.</li></ul><h2 id="게이트웨이-탐색-bonjour" tabindex="-1">게이트웨이 탐색 (Bonjour) <a class="header-anchor" href="#게이트웨이-탐색-bonjour" aria-label="Permalink to &quot;게이트웨이 탐색 (Bonjour)&quot;">​</a></h2><p><code>gateway discover</code>는 게이트웨이 비콘 (<code>_openclaw-gw._tcp</code>)을 스캔합니다.</p><ul><li>멀티캐스트 DNS-SD: <code>local.</code></li><li>유니캐스트 DNS-SD (광역 Bonjour): 도메인을 선택하고 (예: <code>openclaw.internal.</code>) 분할 DNS + DNS 서버를 설정하세요. <a href="/openclaw-docs-ko/gateway/bonjour">/gateway/bonjour</a> 참조</li></ul><p>기본적으로 Bonjour 탐색이 활성화된 게이트웨이만 비콘을 알립니다.</p><p>광역 탐색 레코드에는 다음이 포함됩니다 (TXT):</p><ul><li><code>role</code> (게이트웨이 역할 힌트)</li><li><code>transport</code> (전송 힌트, 예: <code>gateway</code>)</li><li><code>gatewayPort</code> (WebSocket 포트, 보통 <code>18789</code>)</li><li><code>sshPort</code> (선택 사항; 없는 경우 클라이언트 기본 SSH 대상은 <code>22</code>)</li><li><code>tailnetDns</code> (MagicDNS 호스트명, 사용 가능한 경우)</li><li><code>gatewayTls</code> / <code>gatewayTlsSha256</code> (TLS 활성화 + 인증서 지문)</li><li><code>cliPath</code> (광역 존에 작성된 원격 설치 힌트)</li></ul><h3 id="gateway-discover" tabindex="-1"><code>gateway discover</code> <a class="header-anchor" href="#gateway-discover" aria-label="Permalink to &quot;`gateway discover`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> discover</span></span></code></pre></div><p>옵션:</p><ul><li><code>--timeout &lt;ms&gt;</code>: 명령별 타임아웃 (탐색/확인); 기본값 <code>2000</code>.</li><li><code>--json</code>: 기계 판독 가능한 출력 (스타일링/스피너도 비활성화).</li></ul><p>예시:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> discover</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4000</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> discover</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.beacons[].wsUrl&#39;</span></span></code></pre></div><p>참고사항:</p><ul><li>CLI는 <code>local.</code>과 광역 도메인이 활성화된 경우 구성된 광역 도메인을 스캔합니다.</li><li>JSON 출력의 <code>wsUrl</code>은 <code>lanHost</code> 또는 <code>tailnetDns</code>와 같은 TXT 전용 힌트가 아닌 확인된 서비스 엔드포인트에서 파생됩니다.</li><li><code>local.</code> mDNS에서 <code>sshPort</code> 및 <code>cliPath</code>는 <code>discovery.mdns.mode</code>가 <code>full</code>인 경우에만 방송됩니다. 광역 DNS-SD는 여전히 <code>cliPath</code>를 작성하며 <code>sshPort</code>는 거기서도 선택 사항입니다.</li></ul>',83)])])}const g=a(o,[["render",t]]);export{k as __pageData,g as default};
